import { ReactNode } from 'react';
import type { AuthState } from '../../hooks/use-auth';
import './auth-gate.scss';

export default function AuthGate({
  auth,
  children,
}: {
  auth: AuthState;
  children: ReactNode;
}) {
  const { isAuthenticated, isLoading, error } = auth;

  if (isLoading) {
    return (
      <div className="auth-gate">
        <div className="auth-gate__spinner" />
        <p>Signing in…</p>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <div className="auth-gate">
        <h2>eBay Live Agent</h2>
        {error && <p className="auth-gate__error">{error}</p>}
        <p>
          Send <code>/web</code> to the Telegram bot to get a login link.
        </p>
      </div>
    );
  }

  return <>{children}</>;
}
