export const DEFAULT_LANGUAGE_ID = "en";
export const LANGUAGE_STORAGE_KEY = "live_ui_selected_language";

export function getLanguageById(id: string | null | undefined): AppLanguage | null {
  if (!id) {
    return null;
  }

  return APP_LANGUAGES.find((language) => language.id === id) ?? null;
}
