import { useEffect, useMemo, useState } from "react";
import {
  getLiveTraceSessionDetail,
  listLiveTraceSessions,
  type LiveTraceEventDto,
  type LiveTraceSessionDetailDto,
  type LiveTraceSessionDto,
} from "../../lib/api-client";
import "./live-trace-admin.scss";

type FiltersState = {
  userId: string;
  selectedLanguage: string;
  stageReached: string;
  terminalReason: string;
};

function formatTimestamp(value: string | null): string {
  if (!value) {
    return "—";
  }

  return new Date(value).toLocaleString();
}

function eventGroupLabel(event: LiveTraceEventDto): string {
  if (event.type.includes("transcript")) {
    return "Transcript";
  }

  if (event.type.includes("tool_call")) {
    return "Tool";
  }

  if (event.type.includes("oauth")) {
    return "OAuth";
  }

  if (event.type.includes("error") || event.type.includes("disconnected")) {
    return "Error / Disconnect";
  }

  return "Event";
}

export default function LiveTraceAdminPage({
  sessionToken,
}: {
  sessionToken: string;
}) {
  const [filters, setFilters] = useState<FiltersState>({
    userId: "",
    selectedLanguage: "",
    stageReached: "",
    terminalReason: "",
  });
  const [sessions, setSessions] = useState<LiveTraceSessionDto[]>([]);
  const [selectedSessionId, setSelectedSessionId] = useState<string | null>(null);
  const [detail, setDetail] = useState<LiveTraceSessionDetailDto | null>(null);
  const [loadingSessions, setLoadingSessions] = useState(false);
  const [loadingDetail, setLoadingDetail] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const selectedSession = useMemo(
    () => sessions.find((session) => session.sessionId === selectedSessionId) ?? detail?.session ?? null,
    [detail?.session, selectedSessionId, sessions],
  );

  useEffect(() => {
    let cancelled = false;
    setLoadingSessions(true);
    setError(null);

    listLiveTraceSessions(sessionToken, filters)
      .then(({ sessions }) => {
        if (cancelled) {
          return;
        }
        setSessions(sessions);
        if (!selectedSessionId && sessions[0]) {
          setSelectedSessionId(sessions[0].sessionId);
        }
      })
      .catch((nextError) => {
        if (!cancelled) {
          setError(nextError.message ?? "Failed to load trace sessions");
        }
      })
      .finally(() => {
        if (!cancelled) {
          setLoadingSessions(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [filters, selectedSessionId, sessionToken]);

  useEffect(() => {
    if (!selectedSessionId) {
      setDetail(null);
      return;
    }

    let cancelled = false;
    setLoadingDetail(true);
    getLiveTraceSessionDetail(sessionToken, selectedSessionId)
      .then((nextDetail) => {
        if (!cancelled) {
          setDetail(nextDetail);
        }
      })
      .catch((nextError) => {
        if (!cancelled) {
          setError(nextError.message ?? "Failed to load session detail");
        }
      })
      .finally(() => {
        if (!cancelled) {
          setLoadingDetail(false);
        }
      });

    return () => {
      cancelled = true;
    };
  }, [selectedSessionId, sessionToken]);

  return (
    <div className="trace-admin">
      <header className="trace-admin__header">
        <div>
          <p className="trace-admin__eyebrow">Operator Replay</p>
          <h1>Live Trace</h1>
          <p>Replay sessions, transcripts, tool calls, disconnect reasons, and version tags.</p>
        </div>
      </header>

      <section className="trace-admin__filters">
        <input
          value={filters.userId}
          onChange={(event) =>
            setFilters((current) => ({ ...current, userId: event.target.value }))
          }
          placeholder="User ID"
        />
        <input
          value={filters.selectedLanguage}
          onChange={(event) =>
            setFilters((current) => ({
              ...current,
              selectedLanguage: event.target.value,
            }))
          }
          placeholder="Language"
        />
        <input
          value={filters.stageReached}
          onChange={(event) =>
            setFilters((current) => ({ ...current, stageReached: event.target.value }))
          }
          placeholder="Stage"
        />
        <input
          value={filters.terminalReason}
          onChange={(event) =>
            setFilters((current) => ({
              ...current,
              terminalReason: event.target.value,
            }))
          }
          placeholder="Terminal reason"
        />
      </section>

      {error ? <p className="trace-admin__error">{error}</p> : null}

      <div className="trace-admin__grid">
        <section className="trace-admin__panel">
          <div className="trace-admin__panel-head">
            <h2>Sessions</h2>
            <span>{loadingSessions ? "Loading…" : `${sessions.length} found`}</span>
          </div>
          <div className="trace-admin__session-list">
            {sessions.map((session) => (
              <button
                key={session.sessionId}
                type="button"
                className={
                  session.sessionId === selectedSessionId
                    ? "trace-admin__session is-selected"
                    : "trace-admin__session"
                }
                onClick={() => setSelectedSessionId(session.sessionId)}
              >
                <strong>{session.selectedLanguage}</strong>
                <span>{session.userId}</span>
                <span>{session.latestStage}</span>
                <span>{formatTimestamp(session.startedAt)}</span>
              </button>
            ))}
          </div>
        </section>

        <section className="trace-admin__panel trace-admin__panel--detail">
          <div className="trace-admin__panel-head">
            <h2>Detail</h2>
            <span>{loadingDetail ? "Loading…" : selectedSessionId ?? "No session selected"}</span>
          </div>

          {selectedSession ? (
            <>
              <section className="trace-admin__summary">
                <div>
                  <span>Started</span>
                  <strong>{formatTimestamp(selectedSession.startedAt)}</strong>
                </div>
                <div>
                  <span>Ended</span>
                  <strong>{formatTimestamp(selectedSession.endedAt)}</strong>
                </div>
                <div>
                  <span>Revision</span>
                  <strong>{selectedSession.backendRevision}</strong>
                </div>
                <div>
                  <span>Frontend</span>
                  <strong>{selectedSession.frontendBuild}</strong>
                </div>
                <div>
                  <span>Prompt</span>
                  <strong>{selectedSession.promptVersion}</strong>
                </div>
                <div>
                  <span>Tools</span>
                  <strong>{selectedSession.toolSchemaVersion}</strong>
                </div>
                <div>
                  <span>Flow</span>
                  <strong>{selectedSession.flowVersion}</strong>
                </div>
                <div>
                  <span>Terminal</span>
                  <strong>{selectedSession.terminalReason ?? "—"}</strong>
                </div>
              </section>

              <section className="trace-admin__stages">
                {selectedSession.stagesVisited.map((stage) => (
                  <span key={stage}>{stage}</span>
                ))}
              </section>
            </>
          ) : null}

          <section className="trace-admin__timeline">
            {(detail?.events ?? []).map((event) => (
              <article key={`${event.sessionId}:${event.seq}`} className="trace-admin__event">
                <div className="trace-admin__event-topline">
                  <span>{eventGroupLabel(event)}</span>
                  <span>{event.type}</span>
                  <span>{event.stage}</span>
                  <span>{formatTimestamp(event.at)}</span>
                </div>
                <pre>{JSON.stringify(event.payload, null, 2)}</pre>
              </article>
            ))}
          </section>
        </section>
      </div>
    </div>
  );
}
