import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  appendLiveTraceEvents,
  createLiveTraceSession,
  getConfiguredBackendUrl,
  writeLiveTraceSummary,
  type LiveTraceStage,
  type LiveTraceSummaryCreateDto,
} from "../lib/api-client";
import {
  createTraceSessionId,
  FLOW_VERSION,
  FRONTEND_BUILD,
  PROMPT_VERSION,
  TOOL_SCHEMA_VERSION,
  TRACE_SESSION_STORAGE_KEY,
  type TraceEventInput,
} from "../lib/live-trace";

type UseLiveTraceOptions = {
  sessionToken: string | null;
  selectedLanguage: string | null;
};

type SessionMetrics = {
  connectedToEbay: boolean | null;
  sellerSetupCompleted: boolean | null;
  listingStarted: boolean | null;
  publishReached: boolean | null;
};

function getOrCreateStoredSessionId(): string {
  const stored = window.sessionStorage.getItem(TRACE_SESSION_STORAGE_KEY);
  if (stored) {
    return stored;
  }

  const sessionId = createTraceSessionId();
  window.sessionStorage.setItem(TRACE_SESSION_STORAGE_KEY, sessionId);
  return sessionId;
}

function buildSummary(
  terminalReason: LiveTraceSummaryCreateDto["terminalReason"],
  metrics: SessionMetrics,
  stagesVisited: LiveTraceStage[],
  startedAtMs: number | null
): LiveTraceSummaryCreateDto {
  return {
    terminalReason,
    endedAt: new Date().toISOString(),
    durationMs: startedAtMs ? Date.now() - startedAtMs : null,
    connectedToEbay: metrics.connectedToEbay,
    sellerSetupCompleted: metrics.sellerSetupCompleted,
    listingStarted: metrics.listingStarted,
    publishReached: metrics.publishReached,
    stagesVisited,
  };
}

export function useLiveTrace({
  sessionToken,
  selectedLanguage,
}: UseLiveTraceOptions) {
  const [sessionId] = useState(() => getOrCreateStoredSessionId());
  const [traceReady, setTraceReady] = useState(false);
  const queuedEventsRef = useRef<TraceEventInput[]>([]);
  const seqRef = useRef(1);
  const sessionCreatedRef = useRef(false);
  const creatingSessionRef = useRef(false);
  const summaryWrittenRef = useRef(false);
  const stagesVisitedRef = useRef<Set<LiveTraceStage>>(new Set(["language_select"]));
  const startedAtMsRef = useRef<number | null>(null);
  const metricsRef = useRef<SessionMetrics>({
    connectedToEbay: null,
    sellerSetupCompleted: null,
    listingStarted: null,
    publishReached: null,
  });
  const selectedLanguageRef = useRef<string | null>(null);

  const flush = useCallback(async () => {
    if (!sessionToken || !sessionCreatedRef.current || queuedEventsRef.current.length === 0) {
      return;
    }

    const events = queuedEventsRef.current;
    queuedEventsRef.current = [];

    try {
      await appendLiveTraceEvents(sessionToken, sessionId, events);
    } catch (error) {
      console.warn("[live-trace] flush failed", error);
      queuedEventsRef.current = [...events, ...queuedEventsRef.current];
    }
  }, [sessionId, sessionToken]);

  const flushViaBeacon = useCallback(
    (summary?: LiveTraceSummaryCreateDto) => {
      if (!sessionToken || !sessionCreatedRef.current) {
        return;
      }

      const backendUrl = getConfiguredBackendUrl();
      const pendingEvents = queuedEventsRef.current;
      if (pendingEvents.length > 0 && typeof navigator.sendBeacon === "function") {
        const payload = JSON.stringify({
          sessionId,
          sessionToken,
          events: pendingEvents,
        });
        const success = navigator.sendBeacon(
          `${backendUrl}/api/live-trace/events`,
          new Blob([payload], { type: "application/json" }),
        );
        if (success) {
          queuedEventsRef.current = [];
        }
      }

      if (summary && !summaryWrittenRef.current && typeof navigator.sendBeacon === "function") {
        const payload = JSON.stringify({
          sessionToken,
          ...summary,
        });
        navigator.sendBeacon(
          `${backendUrl}/api/live-trace/session/${encodeURIComponent(sessionId)}/summary`,
          new Blob([payload], { type: "application/json" }),
        );
        summaryWrittenRef.current = true;
      }
    },
    [sessionId, sessionToken],
  );

  const ensureSession = useCallback(async () => {
    if (
      !sessionToken ||
      !selectedLanguage ||
      sessionCreatedRef.current ||
      creatingSessionRef.current
    ) {
      return;
    }

    creatingSessionRef.current = true;
    try {
      await createLiveTraceSession(sessionToken, {
        sessionId,
        selectedLanguage,
        frontendBuild: FRONTEND_BUILD,
        promptVersion: PROMPT_VERSION,
        toolSchemaVersion: TOOL_SCHEMA_VERSION,
        flowVersion: FLOW_VERSION,
        entry: "telegram_web",
      });
      sessionCreatedRef.current = true;
      if (!startedAtMsRef.current) {
        startedAtMsRef.current = Date.now();
      }
      setTraceReady(true);
    } catch (error) {
      console.warn("[live-trace] session start failed", error);
    } finally {
      creatingSessionRef.current = false;
    }
  }, [selectedLanguage, sessionId, sessionToken]);

  const recordEvent = useCallback(
    (
      type: TraceEventInput["type"],
      stage: TraceEventInput["stage"],
      payload: Record<string, unknown> = {},
    ) => {
      stagesVisitedRef.current.add(stage);
      queuedEventsRef.current.push({
        seq: seqRef.current++,
        at: new Date().toISOString(),
        type,
        stage,
        payload,
        frontendBuild: FRONTEND_BUILD,
        promptVersion: PROMPT_VERSION,
        toolSchemaVersion: TOOL_SCHEMA_VERSION,
        flowVersion: FLOW_VERSION,
      });
    },
    [],
  );

  const setMetric = useCallback(
    (partial: Partial<SessionMetrics>) => {
      metricsRef.current = { ...metricsRef.current, ...partial };
    },
    [],
  );

  const writeSummary = useCallback(
    async (summary: LiveTraceSummaryCreateDto) => {
      if (!sessionToken || !sessionCreatedRef.current || summaryWrittenRef.current) {
        return;
      }

      await flush();
      try {
        await writeLiveTraceSummary(sessionToken, sessionId, summary);
        summaryWrittenRef.current = true;
      } catch (error) {
        console.warn("[live-trace] summary write failed", error);
      }
    },
    [flush, sessionId, sessionToken],
  );

  useEffect(() => {
    void ensureSession();
  }, [ensureSession]);

  useEffect(() => {
    if (!selectedLanguage || selectedLanguageRef.current === selectedLanguage) {
      return;
    }

    selectedLanguageRef.current = selectedLanguage;
    recordEvent("session_started", "language_select", {
      sessionId,
      selectedLanguage,
    });
    recordEvent("language_selected", "language_select", {
      selectedLanguage,
    });
  }, [recordEvent, selectedLanguage, sessionId]);

  useEffect(() => {
    if (!traceReady) {
      return;
    }

    const timer = window.setInterval(() => {
      void flush();
    }, 1500);

    return () => window.clearInterval(timer);
  }, [flush, traceReady]);

  useEffect(() => {
    const handlePageHide = () => {
      const summary = buildSummary(
        "user_left",
        metricsRef.current,
        [...stagesVisitedRef.current],
        startedAtMsRef.current,
      );
      flushViaBeacon(summary);
    };

    window.addEventListener("pagehide", handlePageHide);
    return () => window.removeEventListener("pagehide", handlePageHide);
  }, [flushViaBeacon]);

  const api = useMemo(
    () => ({
      sessionId,
      traceReady,
      recordEvent,
      setMetric,
      flush,
      writeSummary,
      buildTerminalSummary: (
        terminalReason: LiveTraceSummaryCreateDto["terminalReason"],
      ) =>
        buildSummary(
          terminalReason,
          metricsRef.current,
          [...stagesVisitedRef.current],
          startedAtMsRef.current,
        ),
    }),
    [flush, recordEvent, sessionId, setMetric, traceReady, writeSummary],
  );

  return api;
}
