export type LayoutBounds = {
  left: number;
  top: number;
  right: number;
  bottom: number;
  width: number;
  height: number;
};

export type LayoutBox = {
  width: number;
  height: number;
};

export type LayoutRect = {
  left: number;
  top: number;
  right: number;
  bottom: number;
  centerX: number;
  centerY: number;
};

export type LayoutItem = {
  id: string;
  preferredX: number;
  preferredY: number;
  box: LayoutBox;
  orderHint?: number;
};

export function parseRotationDegrees(value: string): number {
  return (Number.parseFloat(value) || 0) * (Math.PI / 180);
}

export function rotatedBoxSize(
  width: number,
  height: number,
  angle: number,
): LayoutBox {
  const cos = Math.abs(Math.cos(angle));
  const sin = Math.abs(Math.sin(angle));

  return {
    width: width * cos + height * sin + 10,
    height: width * sin + height * cos + 10,
  };
}

export function intersects(a: LayoutRect, b: LayoutRect, gap = 6): boolean {
  return !(
    a.right + gap < b.left ||
    a.left > b.right + gap ||
    a.bottom + gap < b.top ||
    a.top > b.bottom + gap
  );
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

function findPlacement(
  targetX: number,
  targetY: number,
  box: LayoutBox,
  bounds: LayoutBounds,
  placed: LayoutRect[],
): LayoutRect {
  const maxRadius = Math.max(bounds.width, bounds.height);
  const clampedTargetX = clamp(
    targetX,
    bounds.left + box.width / 2,
    bounds.right - box.width / 2,
  );
  const clampedTargetY = clamp(
    targetY,
    bounds.top + box.height / 2,
    bounds.bottom - box.height / 2,
  );
  let best: { rect: LayoutRect; score: number } | null = null;

  const evaluate = (centerX: number, centerY: number): boolean => {
    const left = centerX - box.width / 2;
    const top = centerY - box.height / 2;
    const rect: LayoutRect = {
      left,
      top,
      right: left + box.width,
      bottom: top + box.height,
      centerX,
      centerY,
    };

    const overlapCount = placed.reduce(
      (count, candidate) => count + (intersects(rect, candidate) ? 1 : 0),
      0,
    );
    const distance =
      Math.abs(centerX - clampedTargetX) * 0.95 +
      Math.abs(centerY - clampedTargetY) * 1.1;
    const score = overlapCount * 10000 + distance;

    if (!best || score < best.score) {
      best = { rect, score };
    }

    return overlapCount === 0;
  };

  if (evaluate(clampedTargetX, clampedTargetY)) {
    return best!.rect;
  }

  for (let radius = 10; radius <= maxRadius; radius += 10) {
    for (let step = 0; step < 18; step += 1) {
      const angle = (Math.PI * 2 * step) / 18;
      const centerX = clamp(
        clampedTargetX + Math.cos(angle) * radius,
        bounds.left + box.width / 2,
        bounds.right - box.width / 2,
      );
      const centerY = clamp(
        clampedTargetY + Math.sin(angle) * radius * 0.82,
        bounds.top + box.height / 2,
        bounds.bottom - box.height / 2,
      );

      if (evaluate(centerX, centerY)) {
        return best!.rect;
      }
    }
  }

  return best!.rect;
}

export function placeWords(
  items: LayoutItem[],
  bounds: LayoutBounds,
): Record<string, LayoutRect> {
  const placed: LayoutRect[] = [];
  const positions: Record<string, LayoutRect> = {};

  const sorted = [...items].sort((a, b) => {
    const areaDiff = b.box.width * b.box.height - a.box.width * a.box.height;
    if (areaDiff !== 0) {
      return areaDiff;
    }

    return (a.orderHint ?? 0) - (b.orderHint ?? 0);
  });

  for (const item of sorted) {
    const targetX = bounds.left + (bounds.width * item.preferredX) / 100;
    const targetY = bounds.top + (bounds.height * item.preferredY) / 100;
    const rect = findPlacement(targetX, targetY, item.box, bounds, placed);
    placed.push(rect);
    positions[item.id] = rect;
  }

  return positions;
}
