import type {
  LiveTraceEventCreateDto,
  LiveTraceStage,
  LiveTraceSummaryCreateDto,
} from "./api-client";

export const TRACE_SESSION_STORAGE_KEY = "live_trace_session_id";

export const PROMPT_VERSION = "live-onboarding-v1";
export const FLOW_VERSION = "language-first-live-onboarding-v1";
export const TOOL_SCHEMA_VERSION = "live-onboarding-tools-v1";
export const FRONTEND_BUILD =
  process.env.REACT_APP_FRONTEND_BUILD?.trim() || "web-dev";

export type TraceStage = LiveTraceStage;
export type TraceSummary = LiveTraceSummaryCreateDto;
export type TraceEventInput = LiveTraceEventCreateDto;

export function createTraceSessionId(): string {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }

  return `trace-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
}
