import type { Schema, Tool } from "@google/genai";

function objectSchema(
  properties: Record<string, Schema>,
  overrides: Partial<Schema> = {},
): Schema {
  return {
    type: "OBJECT",
    properties,
    ...overrides,
  } as Schema;
}

function stringSchema(
  description: string,
  overrides: Partial<Schema> = {},
): Schema {
  return {
    type: "STRING",
    description,
    ...overrides,
  } as Schema;
}

function booleanSchema(description: string): Schema {
  return {
    type: "BOOLEAN",
    description,
  } as Schema;
}

function numberSchema(description: string): Schema {
  return {
    type: "NUMBER",
    description,
  } as Schema;
}

export function buildOnboardingTools(): Tool[] {
  return [
    {
      functionDeclarations: [
        {
          name: "get_onboarding_status",
          description:
            "Get the current eBay connection state and seller onboarding state for this user.",
          parameters: objectSchema({}),
        },
        {
          name: "create_ebay_connect_url",
          description:
            "Create a fresh eBay OAuth login URL after the user agrees to connect their account.",
          parameters: objectSchema({
            reason: stringSchema(
              "Short internal reason for why the login is being requested.",
            ),
          }),
        },
        {
          name: "save_onboarding_answers",
          description:
            "Save structured onboarding answers gathered from the user conversation.",
          parameters: objectSchema({
            city: stringSchema(
              "User city in free text. This is conversational context and may be stored only client-side.",
            ),
            shippingCountry: stringSchema(
              "Two-letter shipping country code if the user provided it or if it is confidently known.",
            ),
            postalCode: stringSchema(
              "Postal or ZIP code the seller usually ships from.",
            ),
            acceptsReturns: booleanSchema(
              "Whether the seller accepts returns.",
            ),
            shippingPreference: stringSchema(
              "Preferred shipping policy style.",
              { enum: ["free", "flat_rate", "calculated"] },
            ),
            flatRateShippingUsd: numberSchema(
              "Flat shipping amount in USD. Only use this when shippingPreference is flat_rate.",
            ),
          }),
        },
        {
          name: "prepare_ebay_seller_account",
          description:
            "Prepare or verify eBay seller policies after the required seller setup information is available.",
          parameters: objectSchema({}),
        },
      ],
    },
  ];
}
