const HOSTED_BACKEND_URL =
  'https://live-agent-backend-44dyqtldla-ew.a.run.app';

function getBackendUrl(): string {
  const configuredUrl = process.env.REACT_APP_BACKEND_URL?.trim();
  if (configuredUrl) {
    return configuredUrl.replace(/\/+$/g, '');
  }

  if (typeof window !== 'undefined') {
    const { hostname, origin } = window.location;
    if (hostname === 'gagarinyury.github.io') {
      return HOSTED_BACKEND_URL;
    }

    if (hostname === 'localhost' || hostname === '127.0.0.1') {
      return 'http://localhost:3101';
    }

    return origin.replace(/\/+$/g, '');
  }

  return 'http://localhost:3101';
}

export function getConfiguredBackendUrl(): string {
  return getBackendUrl();
}

