import type { LiveClientToolResponse, LiveServerToolCall } from "@google/genai";
import {
  type LiveTraceStage,
  getEbayConnectUrl,
  getEbayStatus,
  patchSellerProfile,
  prepareSellerAccount,
} from "./api-client";

const EBAY_SELLER_HUB_URL = "https://www.ebay.com/sh/ovw";

export type OnboardingActionCard = {
  kind: "connect" | "manual-approval";
  title: string;
  description: string;
  buttonLabel: string;
  href: string;
};

type HandleOnboardingToolCallsOptions = {
  toolCall: LiveServerToolCall;
  sessionToken: string;
  setActionCard: (card: OnboardingActionCard | null) => void;
  onTraceEvent?: (
    type:
      | "tool_call_requested"
      | "tool_call_resolved"
      | "tool_call_failed"
      | "oauth_started",
    stage: LiveTraceStage,
    payload?: Record<string, unknown>,
  ) => void;
};

function toErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }

  return String(error);
}

function buildManualApprovalCard(errorMessage: string | null): OnboardingActionCard {
  return {
    kind: "manual-approval",
    title: "Finish eBay approval",
    description:
      errorMessage ||
      "Open eBay Seller Hub, finish the required policy approvals, then come back here.",
    buttonLabel: "Open eBay Seller Hub",
    href: EBAY_SELLER_HUB_URL,
  };
}

export async function handleOnboardingToolCalls({
  toolCall,
  sessionToken,
  setActionCard,
  onTraceEvent,
}: HandleOnboardingToolCallsOptions): Promise<LiveClientToolResponse> {
  const responses: NonNullable<LiveClientToolResponse["functionResponses"]> = [];

  for (const functionCall of toolCall.functionCalls ?? []) {
    let result: Record<string, unknown>;
    const startedAt = Date.now();
    const stage: LiveTraceStage =
      functionCall.name === "prepare_ebay_seller_account" ||
      functionCall.name === "save_onboarding_answers" ||
      functionCall.name === "get_onboarding_status"
        ? "seller_setup"
        : "connect";

    try {
      console.info("[live-tool] request", functionCall.name, functionCall.args ?? {});
      onTraceEvent?.("tool_call_requested", stage, {
        name: functionCall.name,
        args: functionCall.args ?? {},
      });

      switch (functionCall.name) {
        case "get_onboarding_status": {
          result = await getEbayStatus(sessionToken);
          if (result.connected) {
            setActionCard(null);
          }
          break;
        }
        case "create_ebay_connect_url": {
          const reason =
            typeof functionCall.args?.reason === "string"
              ? functionCall.args.reason
              : undefined;
          result = await getEbayConnectUrl(sessionToken, reason);
          setActionCard({
            kind: "connect",
            title: "Connect eBay",
            description:
              "Continue in the secure eBay window, then return here to keep going.",
            buttonLabel: "Connect eBay",
            href: String(result.connectUrl),
          });
          onTraceEvent?.("oauth_started", "connect", {
            href: String(result.connectUrl),
          } as Record<string, unknown>);
          break;
        }
        case "save_onboarding_answers": {
          const args = functionCall.args ?? {};
          result = await patchSellerProfile(sessionToken, {
            shippingCountry:
              typeof args.shippingCountry === "string"
                ? args.shippingCountry
                : undefined,
            postalCode:
              typeof args.postalCode === "string" ? args.postalCode : undefined,
            acceptsReturns:
              typeof args.acceptsReturns === "boolean"
                ? args.acceptsReturns
                : undefined,
            shippingPreference:
              typeof args.shippingPreference === "string"
                ? args.shippingPreference
                : undefined,
            flatRateShippingUsd:
              typeof args.flatRateShippingUsd === "number"
                ? args.flatRateShippingUsd
                : undefined,
            saveIfComplete: true,
          });
          break;
        }
        case "prepare_ebay_seller_account": {
          const prepared = await prepareSellerAccount(sessionToken);
          result = prepared;
          if (!prepared.ready) {
            const blockerMessage =
              prepared.sellingPolicyProgram.errorMessage ||
              prepared.merchantLocation.errorMessage ||
              prepared.paymentPolicy.errorMessage ||
              prepared.returnPolicy.errorMessage ||
              prepared.fulfillmentPolicy.errorMessage ||
              null;
            setActionCard(buildManualApprovalCard(blockerMessage));
          } else {
            setActionCard(null);
          }
          break;
        }
        default: {
          result = { error: `Unknown tool: ${functionCall.name}` };
          break;
        }
      }
    } catch (error: unknown) {
      const message = toErrorMessage(error);
      console.error("[live-tool] error", functionCall.name, message);
      onTraceEvent?.("tool_call_failed", stage, {
        name: functionCall.name,
        error: message,
        latencyMs: Date.now() - startedAt,
      });
      result = { error: message };
    }

    console.info("[live-tool] response", functionCall.name, result);
    onTraceEvent?.("tool_call_resolved", stage, {
      name: functionCall.name,
      result,
      latencyMs: Date.now() - startedAt,
    });
    responses.push({
      id: functionCall.id,
      name: functionCall.name,
      response: { result },
    });
  }

  return {
    functionResponses: responses,
  };
}
