import {
  createContext,
  FC,
  ReactNode,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";
import { useLiveAPI, UseLiveAPIResults } from "../hooks/use-live-api";
import { LiveClientOptions } from "../types";
import { getEphemeralToken } from "../lib/api-client";

const LiveAPIContext = createContext<UseLiveAPIResults | undefined>(undefined);

export type LiveAPIProviderProps = {
  children: ReactNode;
  model: string;
  sessionToken: string | null;
  onTokenEvent?: (event: "requested" | "received" | "failed", details?: Record<string, unknown>) => void;
};

export const LiveAPIProvider: FC<LiveAPIProviderProps> = ({
  model,
  sessionToken,
  onTokenEvent,
  children,
}) => {
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (!sessionToken) return;
    let cancelled = false;
    onTokenEvent?.("requested");

    getEphemeralToken(sessionToken)
      .then(({ token }) => {
        if (!cancelled) {
          setApiKey(token);
          onTokenEvent?.("received");
        }
      })
      .catch((err) => {
        if (!cancelled) {
          setError(err.message);
          onTokenEvent?.("failed", { error: err.message });
        }
      });

    return () => {
      cancelled = true;
    };
  }, [onTokenEvent, sessionToken]);

  const options = useMemo<LiveClientOptions | null>(
    () =>
      apiKey
        ? {
            apiKey,
            httpOptions: { apiVersion: "v1alpha" },
          }
        : null,
    [apiKey],
  );

  const liveAPI = useLiveAPI(options, model);

  if (error) {
    return <div style={{ color: "red", padding: 24 }}>Token error: {error}</div>;
  }

  if (!options) {
    return (
      <div style={{ color: "var(--gray-300)", padding: 24 }}>
        Loading ephemeral token…
      </div>
    );
  }

  return (
    <LiveAPIContext.Provider value={liveAPI}>
      {children}
    </LiveAPIContext.Provider>
  );
};

export const useLiveAPIContext = () => {
  const context = useContext(LiveAPIContext);
  if (!context) {
    throw new Error("useLiveAPIContext must be used within a LiveAPIProvider");
  }
  return context;
};
