import { useCallback, useEffect, useState } from 'react';
import { exchangeLoginToken } from '../lib/api-client';

export type AuthState = {
  sessionToken: string | null;
  userId: number | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  error: string | null;
};

type UseAuthOptions = {
  onLoginHashDetected?: (token: string) => void;
  onExchangeStart?: () => void;
  onExchangeSucceeded?: (result: { sessionToken: string; userId: number }) => void;
  onExchangeFailed?: (error: Error) => void;
};

const SESSION_KEY = 'live_session_token';
const USER_KEY = 'live_user_id';

export function useAuth(options: UseAuthOptions = {}): AuthState & { logout: () => void } {
  const [state, setState] = useState<AuthState>({
    sessionToken: sessionStorage.getItem(SESSION_KEY),
    userId: sessionStorage.getItem(USER_KEY)
      ? Number(sessionStorage.getItem(USER_KEY))
      : null,
    isAuthenticated: !!sessionStorage.getItem(SESSION_KEY),
    isLoading: false,
    error: null,
  });

  const logout = useCallback(() => {
    sessionStorage.removeItem(SESSION_KEY);
    sessionStorage.removeItem(USER_KEY);
    setState({
      sessionToken: null,
      userId: null,
      isAuthenticated: false,
      isLoading: false,
      error: null,
    });
  }, []);

  useEffect(() => {
    const hash = window.location.hash;
    const match = hash.match(/^#login=(.+)$/);
    if (!match) return;

    const token = match[1];
    options.onLoginHashDetected?.(token);
    // Clear the hash so the token isn't visible / bookmarkable
    window.history.replaceState(null, '', window.location.pathname);

    setState((s) => ({ ...s, isLoading: true, error: null }));
    options.onExchangeStart?.();

    exchangeLoginToken(token)
      .then(({ sessionToken, userId }) => {
        sessionStorage.setItem(SESSION_KEY, sessionToken);
        sessionStorage.setItem(USER_KEY, String(userId));
        options.onExchangeSucceeded?.({ sessionToken, userId: Number(userId) });
        setState({
          sessionToken,
          userId: Number(userId),
          isAuthenticated: true,
          isLoading: false,
          error: null,
        });
      })
      .catch((err) => {
        options.onExchangeFailed?.(
          err instanceof Error ? err : new Error(String(err)),
        );
        setState({
          sessionToken: null,
          userId: null,
          isAuthenticated: false,
          isLoading: false,
          error: err.message ?? 'Login failed',
        });
      });
  }, [
    options,
  ]);

  return { ...state, logout };
}
