const GEMINI_MODEL =
  process.env.REACT_APP_GEMINI_MODEL ||
  "gemini-2.5-flash-native-audio-preview-12-2025";

function getStoredLanguageId(): string | null {
  const stored = window.localStorage.getItem(LANGUAGE_STORAGE_KEY);
  return getLanguageById(stored) ? stored : null;
}

function isLiveTraceAdminRoute(): boolean {
  const hashPath = window.location.hash.startsWith("#/")
    ? window.location.hash.slice(1)
    : window.location.hash;

  return (
    window.location.pathname.endsWith("/admin/live-trace") ||
    hashPath.startsWith("/admin/live-trace")
  );
}

function extractAssistantText(content: LiveServerContent): string {
  const text = content.modelTurn?.parts
    ?.map((part) => {
      if (typeof part.text !== "string") {
        return "";
      }

      return part.text.replace(/\*\*/g, "").trim();
    })
    .filter(Boolean)
    .join("\n")
    .trim();

  return text || "";
}

function getStatusCopy(
  status: "connected" | "connecting" | "disconnected",
  lastError: string | null,
  actionCard: OnboardingActionCard | null,
): string {
  if (lastError) {
    return lastError;
  }

  if (actionCard?.kind === "connect") {
    return "Continue in the secure eBay window, then return here to keep going.";
  }

  if (actionCard?.kind === "manual-approval") {
    return "eBay still needs a one-time approval step before listing can continue.";
  }

  if (status === "connecting") {
    return "Opening the live voice session and preparing the first onboarding question.";
  }

  if (status === "connected") {
    return "Speak naturally. The assistant will guide the seller setup step by step.";
  }

  return "The voice session is paused. Use play to reconnect.";
}

function LanguageCloud({
  selectedLanguageId,
  onSelect,
}: {
  selectedLanguageId: string | null;
  onSelect: (language: AppLanguage) => void;
}) {
  const screenRef = useRef<HTMLDivElement>(null);
  const buttonRefs = useRef<Record<string, HTMLButtonElement | null>>({});
  const [positions, setPositions] = useState<Record<string, { left: number; top: number }>>(
    {},
  );

  useLayoutEffect(() => {
    const screen = screenRef.current;
    if (!screen) {
      return;
    }

    let frame = 0;

    const requestLayout = () => {
      if (frame) {
        cancelAnimationFrame(frame);
      }

      frame = window.requestAnimationFrame(() => {
        const width = screen.clientWidth;
        const height = screen.clientHeight;
        const bounds = {
          left: 16,
          top: 84,
          right: width - 16,
          bottom: height - 72,
          width: width - 32,
          height: height - 156,
        };

        const measured = APP_LANGUAGES.map((language, index) => {
          const button = buttonRefs.current[language.id];
          if (!button) {
            return null;
          }

          return {
            id: language.id,
            preferredX: language.preferredX,
            preferredY: language.preferredY,
            orderHint: index,
            box: rotatedBoxSize(
              button.offsetWidth,
              button.offsetHeight,
              parseRotationDegrees(language.rotation),
            ),
          };
        }).filter((item): item is NonNullable<typeof item> => Boolean(item));

        const nextPositions = placeWords(measured, bounds);
        setPositions(
          Object.fromEntries(
            Object.entries(nextPositions).map(([id, rect]) => [
              id,
              { left: rect.centerX, top: rect.centerY },
            ]),
          ),
        );
      });
    };

    if (document.fonts?.ready) {
      document.fonts.ready.then(requestLayout);
    } else {
      requestLayout();
    }

    window.addEventListener("resize", requestLayout);
    return () => {
      if (frame) {
        cancelAnimationFrame(frame);
      }
      window.removeEventListener("resize", requestLayout);
    };
  }, [selectedLanguageId]);

  return (
    <section
      ref={screenRef}
      className={cn("language-screen", { "has-selection": !!selectedLanguageId })}
    >
      <p className="language-screen__eyebrow">Choose your language</p>
      <p className="language-screen__hint">Tap to begin</p>

      {APP_LANGUAGES.map((language, index) => {
        const position = positions[language.id];
        const style: CSSProperties = {
          "--language-rotation": language.rotation,
          fontFamily: language.fontFamily,
          fontWeight: language.fontWeight,
          fontStyle: language.fontStyle,
          fontSize: `${language.fontSize}px`,
          animationDelay: `${index * 0.038}s`,
        } as CSSProperties;

        if (position) {
          style.left = `${position.left}px`;
          style.top = `${position.top}px`;
        } else {
          style.left = `${language.preferredX}%`;
          style.top = `${language.preferredY}%`;
        }

        return (
          <button
            key={language.id}
            ref={(node) => {
              buttonRefs.current[language.id] = node;
            }}
            type="button"
            className={cn("language-word", {
              "is-selected": selectedLanguageId === language.id,
            })}
            aria-label={`Speak ${language.nativeLabel}`}
            style={style}
            onClick={() => onSelect(language)}
          >
            <span className="language-word__main">{language.displayWord}</span>
            <span className="language-word__sub">{language.code}</span>
          </button>
        );
      })}
    </section>
  );
}

function ActionCardView({
  actionCard,
  onClick,
}: {
  actionCard: OnboardingActionCard;
  onClick?: () => void;
}) {
  return (
    <article className="action-card">
      <p className="action-card__eyebrow">
        {actionCard.kind === "connect" ? "eBay login" : "Approval step"}
      </p>
      <h3>{actionCard.title}</h3>
      <p>{actionCard.description}</p>
      <a
        className="action-card__button"
        href={actionCard.href}
        target="_blank"
        rel="noreferrer"
        onClick={onClick}
      >
        {actionCard.buttonLabel}
      </a>
    </article>
  );
}

function LiveWorkspace({
  sessionToken,
  selectedLanguageId,
  setSelectedLanguageId,
  trace,
}: {
  sessionToken: string;
  selectedLanguageId: string | null;
  setSelectedLanguageId: (languageId: string | null) => void;
  trace: ReturnType<typeof useLiveTrace>;
}) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [languagePickerOpen, setLanguagePickerOpen] = useState(
    selectedLanguageId === null,
  );
  const [connectionNonce, setConnectionNonce] = useState(0);
  const [pendingAutoStartKey, setPendingAutoStartKey] = useState<string | null>(
    selectedLanguageId ? `${selectedLanguageId}:0` : null,
  );
  const [videoStream, setVideoStream] = useState<MediaStream | null>(null);
  const [assistantText, setAssistantText] = useState("");
  const [actionCard, setActionCard] = useState<OnboardingActionCard | null>(null);
  const kickoffSentRef = useRef(false);
  const actionCardRef = useRef<OnboardingActionCard | null>(null);

  const {
    client,
    config,
    setConfig,
    connected,
    status,
    lastError,
    connect,
    disconnect,
  } = useLiveAPIContext();

  const selectedLanguage =
    getLanguageById(selectedLanguageId) ?? getLanguageById(DEFAULT_LANGUAGE_ID);
  const selectionKey = selectedLanguage
    ? `${selectedLanguage.id}:${connectionNonce}`
    : null;
  const statusLabel =
    status === "connected"
      ? "Connected"
      : status === "connecting"
        ? "Connecting"
        : "Disconnected";
  const statusCopy = getStatusCopy(status, lastError, actionCard);

  useEffect(() => {
    actionCardRef.current = actionCard;
  }, [actionCard]);

  useEffect(() => {
    setLanguagePickerOpen(selectedLanguageId === null);
  }, [selectedLanguageId]);

  useEffect(() => {
    if (!selectedLanguage || languagePickerOpen || !selectionKey) {
      return;
    }

    setConfig(buildOnboardingConfig(selectedLanguage));
    kickoffSentRef.current = false;
  }, [languagePickerOpen, selectedLanguage, selectionKey, setConfig]);

  useEffect(() => {
    if (!selectedLanguage || !selectionKey || languagePickerOpen) {
      return;
    }

    const expectedInstruction = buildOnboardingSystemInstruction(selectedLanguage);
    if (
      pendingAutoStartKey !== selectionKey ||
      config.systemInstruction !== expectedInstruction
    ) {
      return;
    }

    setPendingAutoStartKey(null);
    trace.recordEvent("live_connect_started", "live_connect", {
      language: selectedLanguage.englishName,
      frontendBuild: FRONTEND_BUILD,
    });
    void connect().catch((error: unknown) => {
      trace.recordEvent("session_error", "live_connect", {
        message: error instanceof Error ? error.message : String(error),
      });
    });
  }, [
    config.systemInstruction,
    connect,
    languagePickerOpen,
    pendingAutoStartKey,
    selectedLanguage,
    selectionKey,
    trace,
  ]);

  useEffect(() => {
    if (status !== "connected") {
      kickoffSentRef.current = false;
      return;
    }

    if (!selectedLanguage || kickoffSentRef.current) {
      return;
    }

    kickoffSentRef.current = true;
    client.send({ text: buildKickoffTurn(selectedLanguage) });
  }, [client, selectedLanguage, status]);

  useEffect(() => {
    const onToolCall = async (
      toolCall: Parameters<typeof handleOnboardingToolCalls>[0]["toolCall"],
    ) => {
      const response = await handleOnboardingToolCalls({
        toolCall,
        sessionToken,
        setActionCard,
        onTraceEvent: (type, stage, payload = {}) => {
          if (
            payload.name === "get_onboarding_status" &&
            payload.result &&
            typeof payload.result === "object"
          ) {
            const result = payload.result as {
              connected?: boolean;
              seller?: { onboardingCompleted?: boolean };
            };
            if (typeof result.connected === "boolean") {
              trace.setMetric({ connectedToEbay: result.connected });
              if (result.connected && actionCardRef.current?.kind === "connect") {
                trace.recordEvent("oauth_returned", "connect", { connected: true });
              }
            }
            if (typeof result.seller?.onboardingCompleted === "boolean") {
              trace.setMetric({
                sellerSetupCompleted: result.seller.onboardingCompleted,
              });
            }
          }

          if (
            payload.name === "prepare_ebay_seller_account" &&
            payload.result &&
            typeof payload.result === "object" &&
            (payload.result as { ready?: boolean }).ready
          ) {
            trace.setMetric({ sellerSetupCompleted: true, listingStarted: true });
            trace.recordEvent("seller_setup_completed", "seller_setup", {
              ready: true,
            });
            trace.recordEvent("listing_stage_entered", "listing", {
              source: "prepare_ebay_seller_account",
            });
          }

          trace.recordEvent(type, stage, payload);
        },
      });
      client.sendToolResponse(response);
    };

    const onContent = (content: LiveServerContent) => {
      const nextText = extractAssistantText(content);
      if (!nextText) {
        return;
      }

      setAssistantText(nextText);
    };

    const onOpen = () => {
      trace.recordEvent("live_connected", "live_connect", {
        transport: "gemini-live",
      });
    };

    const onSetupComplete = () => {
      trace.recordEvent("setup_complete", "live_connect", {});
    };

    const onClose = (event: CloseEvent) => {
      trace.recordEvent("live_disconnected", "ended", {
        code: event.code,
        reason: event.reason || null,
      });
    };

    const onError = (event: ErrorEvent) => {
      trace.recordEvent("session_error", "live_connect", {
        message: event.message || "Live connection failed",
      });
    };

    const onInputTranscription = (transcription: {
      text?: string;
      finished?: boolean;
    }) => {
      if (!transcription.finished || !transcription.text?.trim()) {
        return;
      }

      trace.recordEvent("user_transcript_final", "seller_setup", {
        text: transcription.text.trim(),
      });
    };

    const onOutputTranscription = (transcription: {
      text?: string;
      finished?: boolean;
    }) => {
      if (!transcription.finished || !transcription.text?.trim()) {
        return;
      }

      trace.recordEvent("assistant_transcript_final", "seller_setup", {
        text: transcription.text.trim(),
      });
    };

    const onLog = (entry: StreamingLog) => {
      console.info(`[live] ${entry.type}`, entry.message);
    };

    client.on("open", onOpen);
    client.on("setupcomplete", onSetupComplete);
    client.on("close", onClose);
    client.on("error", onError);
    client.on("toolcall", onToolCall);
    client.on("content", onContent);
    client.on("inputtranscription", onInputTranscription);
    client.on("outputtranscription", onOutputTranscription);
    client.on("log", onLog);

    return () => {
      client.off("open", onOpen);
      client.off("setupcomplete", onSetupComplete);
      client.off("close", onClose);
      client.off("error", onError);
      client.off("toolcall", onToolCall);
      client.off("content", onContent);
      client.off("inputtranscription", onInputTranscription);
      client.off("outputtranscription", onOutputTranscription);
      client.off("log", onLog);
    };
  }, [client, sessionToken, trace]);

  useEffect(() => {
    if (!actionCard) {
      return;
    }

    trace.recordEvent(
      "action_card_shown",
      actionCard.kind === "connect" ? "connect" : "seller_setup",
      {
        kind: actionCard.kind,
        title: actionCard.title,
        href: actionCard.href,
      },
    );
  }, [actionCard, trace]);

  const handleLanguageSelect = (language: AppLanguage) => {
    window.localStorage.setItem(LANGUAGE_STORAGE_KEY, language.id);
    setSelectedLanguageId(language.id);
    setLanguagePickerOpen(false);
    setAssistantText("");
    setActionCard(null);
    kickoffSentRef.current = false;
    void disconnect();
    setConnectionNonce((prev) => {
      const next = prev + 1;
      setPendingAutoStartKey(`${language.id}:${next}`);
      return next;
    });
  };

  const reopenLanguagePicker = () => {
    setLanguagePickerOpen(true);
    setActionCard(null);
    void disconnect();
  };

  if (languagePickerOpen || !selectedLanguage) {
    return (
      <LanguageCloud
        selectedLanguageId={selectedLanguageId}
        onSelect={handleLanguageSelect}
      />
    );
  }

  return (
    <div className="app-shell">
      <section className="onboarding-stage">
        <header className="onboarding-stage__header">
          <div>
            <p className="onboarding-stage__eyebrow">eBay Live Seller</p>
            <h1>{selectedLanguage.nativeLabel}</h1>
            <p className="onboarding-stage__copy">
              Conversation stays in {selectedLanguage.nativeLabel}. Listing output
              stays in English.
            </p>
          </div>
          <button
            type="button"
            className="secondary-button"
            onClick={reopenLanguagePicker}
          >
            Change language
          </button>
        </header>

        <section className="status-card">
          <div className="status-card__topline">
            <span className={cn("status-chip", `is-${status}`)}>
              {statusLabel}
            </span>
            <span className="status-card__meta">
              {connected ? "Mic streaming ready" : "Voice session idle"}
            </span>
          </div>
          <p>{statusCopy}</p>
        </section>

        {assistantText ? (
          <section className="assistant-card">
            <p className="assistant-card__eyebrow">Assistant</p>
            <p>{assistantText}</p>
          </section>
        ) : (
          <section className="assistant-card assistant-card--empty">
            <p className="assistant-card__eyebrow">Assistant</p>
            <p>
              After the session opens, the agent will greet the user, guide eBay
              connection if needed, and continue seller setup by voice.
            </p>
          </section>
        )}

        {actionCard ? (
          <ActionCardView
            actionCard={actionCard}
            onClick={() =>
              trace.recordEvent(
                "action_card_clicked",
                actionCard.kind === "connect" ? "connect" : "seller_setup",
                {
                  kind: actionCard.kind,
                  href: actionCard.href,
                },
              )
            }
          />
        ) : null}

        <section className="control-dock">
          <video
            className={cn("stream", {
              hidden: !videoRef.current || !videoStream,
            })}
            ref={videoRef}
            autoPlay
            playsInline
          />
          <ControlTray
            videoRef={videoRef}
            supportsVideo={false}
            onVideoStreamChange={setVideoStream}
          />
        </section>
      </section>
    </div>
  );
}

function App() {
  const [selectedLanguageId, setSelectedLanguageId] = useState<string | null>(
    getStoredLanguageId(),
  );
  const loginStartLoggedRef = useRef(false);
  const loginSuccessLoggedRef = useRef(false);
  const loginFailureLoggedRef = useRef<string | null>(null);
  const selectedLanguage = useMemo(
    () => getLanguageById(selectedLanguageId)?.englishName ?? null,
    [selectedLanguageId],
  );
  const auth = useAuth();
  const trace = useLiveTrace({
    sessionToken: auth.sessionToken,
    selectedLanguage,
  });
  const adminRoute = isLiveTraceAdminRoute();

  useEffect(() => {
    const hash = window.location.hash;
    if (!hash.startsWith("#login=") || loginStartLoggedRef.current) {
      return;
    }

    loginStartLoggedRef.current = true;
    trace.recordEvent("login_exchange_started", "auth", {
      source: "hash",
    });
  }, [trace]);

  useEffect(() => {
    if (auth.isAuthenticated && auth.userId) {
      if (loginSuccessLoggedRef.current) {
        return;
      }
      loginSuccessLoggedRef.current = true;
      trace.recordEvent("login_exchange_succeeded", "auth", {
        userId: auth.userId,
      });
      return;
    }

    if (!auth.isLoading && auth.error && loginFailureLoggedRef.current !== auth.error) {
      loginFailureLoggedRef.current = auth.error;
      trace.recordEvent("login_exchange_failed", "auth", {
        error: auth.error,
      });
    }
  }, [auth.error, auth.isAuthenticated, auth.isLoading, auth.userId, trace]);

  const handleTokenEvent = useCallback(
    (
      event: "requested" | "received" | "failed",
      details?: Record<string, unknown>,
    ) => {
      if (event === "requested") {
        trace.recordEvent("ephemeral_token_requested", "auth", details ?? {});
        return;
      }

      if (event === "received") {
        trace.recordEvent("ephemeral_token_received", "auth", details ?? {});
        return;
      }

      trace.recordEvent("ephemeral_token_failed", "auth", details ?? {});
    },
    [trace],
  );

  return (
    <div className="App">
      <AuthGate auth={auth}>
        {adminRoute && auth.sessionToken ? (
          <LiveTraceAdminPage sessionToken={auth.sessionToken} />
        ) : (
          <LiveAPIProvider
            model={GEMINI_MODEL}
            sessionToken={auth.sessionToken}
            onTokenEvent={handleTokenEvent}
          >
            <LiveWorkspace
              sessionToken={auth.sessionToken!}
              selectedLanguageId={selectedLanguageId}
              setSelectedLanguageId={setSelectedLanguageId}
              trace={trace}
            />
          </LiveAPIProvider>
        )}
      </AuthGate>
    </div>
  );
}

export default App;
